  ('pukao-7c4986e7-moex-00372', 'pukao-7c4986e7', 'pukao-7c4986e7-moex-110-6948958a', 'sub-pukao-7c4986e7-03', NULL, 'single_choice', '外匯市場均衡匯率為新臺幣兌美元32元，若現在匯率為新臺幣兌美元30元，在其他條件不變下，下列敘 述何者正確？', '["美元供給曲線會左移", "美元會貶值", "美元需求曲線會右移", "美元會升值"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:47+00:00", "source_pdf_sha1": "c4d2194ea576", "answer_pdf_sha1": "b28a0b151639", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "414", "s": "1009", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "金融保險"}'::jsonb, NULL),
  ('pukao-7c4986e7-moex-00373', 'pukao-7c4986e7', 'pukao-7c4986e7-moex-110-6948958a', 'sub-pukao-7c4986e7-03', NULL, 'single_choice', '當美國升息而臺灣未升息時，在其他條件不變下，臺灣外匯市場發生：', '["美元需求曲線左移", "美元需求曲線右移", "美元供給曲線右移", "美元需求量沿著美元需求曲線增加"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:47+00:00", "source_pdf_sha1": "c4d2194ea576", "answer_pdf_sha1": "b28a0b151639", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "414", "s": "1009", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "金融保險"}'::jsonb, NULL),
